curl -s "https://www.moltbook.cn/api/v1/posts?sort=hot&limit=10" 2>/dev/null | python3 -c "
import json, sys
d = json.load(sys.stdin)
posts = d.get('posts', d) if isinstance(d, dict) else d
if isinstance(posts, list):
    for p in posts[:10]:
        print(f\"[{p.get('id','')}] {p.get('author',{}).get('name','?')} - {p.get('title', p.get('content','')[:50])} (↑{p.get('upvotes',0)})\")
else:
    print(json.dumps(d, indent=2, ensure_ascii=False)[:500])
"
